Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
                                                     ICmpInst *ICmp2,
                                                     bool IsAnd) {
  // Return (V, CR) for a range check idiom V in CR.
  auto MatchExactRangeCheck =
      [](ICmpInst *ICmp) -> std::optional<std::pair<Value *, ConstantRange>> {
    const APInt *C;
    if (!match(ICmp->getOperand(1), m_APInt(C)))
      return std::nullopt;
    Value *LHS = ICmp->getOperand(0);
    CmpPredicate Pred = ICmp->getPredicate();
    Value *X;
    // Match (x & NegPow2) ==/!= C
    const APInt *Mask;
    if (ICmpInst::isEquality(Pred) &&
        match(LHS, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask)))) &&
        C->countr_zero() >= Mask->countr_zero()) {
      ConstantRange CR(*C, *C - *Mask);
      if (Pred == ICmpInst::ICMP_NE)
        CR = CR.inverse();
      return std::make_pair(X, CR);
    }
    ConstantRange CR = ConstantRange::makeExactICmpRegion(Pred, *C);
    // Match (add X, C1) pred C
    const APInt *C1;
    if (match(LHS, m_AddLike(m_Value(X), m_APInt(C1))))
      return std::make_pair(X, CR.subtract(*C1));
    return std::make_pair(LHS, CR);
  };

  auto RC1 = MatchExactRangeCheck(ICmp1);
  if (!RC1)
    return nullptr;

  auto RC2 = MatchExactRangeCheck(ICmp2);
  if (!RC2)
    return nullptr;

  auto &[V1, CR1] = *RC1;
  auto &[V2, CR2] = *RC2;
  if (V1 != V2)
    return nullptr;

  // For 'and', we use De Morgan's Laws to simplify the implementation.
  if (IsAnd) {
    CR1 = CR1.inverse();
    CR2 = CR2.inverse();
  }

  Type *Ty = V1->getType();
  Value *NewV = V1;
  std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2);
  if (!CR) {
    if (!(ICmp1->hasOneUse() && ICmp2->hasOneUse()) || CR1.isWrappedSet() ||
        CR2.isWrappedSet())
      return nullptr;

    // Check whether we have equal-size ranges that only differ by one bit.
    // In that case we can apply a mask to map one range onto the other.
    APInt LowerDiff = CR1.getLower() ^ CR2.getLower();
    APInt UpperDiff = (CR1.getUpper() - 1) ^ (CR2.getUpper() - 1);
    APInt CR1Size = CR1.getUpper() - CR1.getLower();
    if (!LowerDiff.isPowerOf2() || LowerDiff != UpperDiff ||
        CR1Size != CR2.getUpper() - CR2.getLower())
      return nullptr;

    CR = CR1.getLower().ult(CR2.getLower()) ? CR1 : CR2;
    NewV = Builder.CreateAnd(NewV, ConstantInt::get(Ty, ~LowerDiff));
  }

  if (IsAnd)
    CR = CR->inverse();

  CmpInst::Predicate NewPred;
  APInt NewC, Offset;
  CR->getEquivalentICmp(NewPred, NewC, Offset);

  if (Offset != 0)
    NewV = Builder.CreateAdd(NewV, ConstantInt::get(Ty, Offset));
  return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
}
