  1335 |         match(LHS, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask)))) &&
  1336 |         C->countr_zero() >= Mask->countr_zero()) {
  1337 |       ConstantRange CR(*C, *C - *Mask);
  1338 |       if (Pred == ICmpInst::ICMP_NE)
  1339 |         CR = CR.inverse();
  1340 |       return std::make_pair(X, CR);
  1341 |     }
  1342 |     ConstantRange CR = ConstantRange::makeExactICmpRegion(Pred, *C);
  1343 |     // Match (add X, C1) pred C
  1344 |     const APInt *C1;
  1345 |     if (match(LHS, m_AddLike(m_Value(X), m_APInt(C1))))
  1346 |       return std::make_pair(X, CR.subtract(*C1));
  1347 |     return std::make_pair(LHS, CR);
  1348 |   };
  1349 | 
  1350 |   auto RC1 = MatchExactRangeCheck(ICmp1);
  1351 |   if (!RC1)
  1352 |     return nullptr;
  1353 | 
  1354 |   auto RC2 = MatchExactRangeCheck(ICmp2);
  1355 |   if (!RC2)
  1356 |     return nullptr;
  1357 | 
  1358 |   auto &[V1, CR1] = *RC1;
  1359 |   auto &[V2, CR2] = *RC2;
  1360 |   if (V1 != V2)
  1361 |     return nullptr;
  1362 | 
  1363 |   // For 'and', we use De Morgan's Laws to simplify the implementation.
  1364 |   if (IsAnd) {
  1365 |     CR1 = CR1.inverse();
  1366 |     CR2 = CR2.inverse();
  1367 |   }
  1368 | 
  1369 |   Type *Ty = V1->getType();
  1370 |   Value *NewV = V1;
  1371 |   std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2);
  1372 |   if (!CR) {
  1373 |     if (!(ICmp1->hasOneUse() && ICmp2->hasOneUse()) || CR1.isWrappedSet() ||
  1374 |         CR2.isWrappedSet())
  1375 |       return nullptr;
  1376 | 
  1377 |     // Check whether we have equal-size ranges that only differ by one bit.
  1378 |     // In that case we can apply a mask to map one range onto the other.
  1379 |     APInt LowerDiff = CR1.getLower() ^ CR2.getLower();
  1380 |     APInt UpperDiff = (CR1.getUpper() - 1) ^ (CR2.getUpper() - 1);
  1381 |     APInt CR1Size = CR1.getUpper() - CR1.getLower();
  1382 |     if (!LowerDiff.isPowerOf2() || LowerDiff != UpperDiff ||
  1383 |         CR1Size != CR2.getUpper() - CR2.getLower())
  1384 |       return nullptr;
  1385 | 
  1386 |     CR = CR1.getLower().ult(CR2.getLower()) ? CR1 : CR2;
  1387 |     NewV = Builder.CreateAnd(NewV, ConstantInt::get(Ty, ~LowerDiff));
  1388 |   }
  1389 | 
  1390 |   if (IsAnd)
  1391 |     CR = CR->inverse();
  1392 | 
  1393 |   CmpInst::Predicate NewPred;
  1394 |   APInt NewC, Offset;
  1395 |   CR->getEquivalentICmp(NewPred, NewC, Offset);
  1396 | 
  1397 |   if (Offset != 0)
  1398 |     NewV = Builder.CreateAdd(NewV, ConstantInt::get(Ty, Offset));
  1399 |   return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
  1400 | }
