  1402 | /// Ignore all operations which only change the sign of a value, returning the
  1403 | /// underlying magnitude value.
  1404 | static Value *stripSignOnlyFPOps(Value *Val) {
  1405 |   match(Val, m_FNeg(m_Value(Val)));
  1406 |   match(Val, m_FAbs(m_Value(Val)));
  1407 |   match(Val, m_CopySign(m_Value(Val), m_Value()));
  1408 |   return Val;
  1409 | }
