  1411 | /// Matches canonical form of isnan, fcmp ord x, 0
  1412 | static bool matchIsNotNaN(FCmpInst::Predicate P, Value *LHS, Value *RHS) {
  1413 |   return P == FCmpInst::FCMP_ORD && match(RHS, m_AnyZeroFP());
